#include <stdio.h>

void selectionSort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        int min_idx = i;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] < arr[min_idx]) min_idx = j;
        }
        int t = arr[min_idx]; arr[min_idx] = arr[i]; arr[i] = t;
    }
}

int main() {
    int a[] = {5, 2, 8, 1};
    selectionSort(a, 4);
    return 0;
}
